// Configure target roles to monitor
const targetRoles = ['sales', 'engineering', 'marketing', 'product', 'data'];

const domain = $('🔄 Loop Over Companies').first().json.properties.domain;
const companyName = $('🔄 Loop Over Companies').first().json.properties.name;
const companyId = $('🔄 Loop Over Companies').first().json.properties.hs_object_id;

const allJobs = $input.first().json.data || [];

// Filter jobs matching target roles
const matchingJobs = allJobs.filter(job => {
  const title = (job.title || '').toLowerCase();
  return targetRoles.some(role => title.includes(role));
});

return [{
  json: {
    domain,
    companyName,
    companyId,
    totalJobCount: allJobs.length,
    matchingJobCount: matchingJobs.length,
    matchingJobs: matchingJobs.map(j => j.title),
    targetRoles
  }
}];

// Read historical data from Google Sheets input (connected via merge/lookup)
const current = $input.first().json;
const historicalRows = $('📂 Read Historical Counts').first().json.rows || [];

const domain = current.domain;
const currentCount = current.matchingJobCount;

// Find previous count for this domain
const prevRow = historicalRows.find(r => r.domain === domain);
const previousCount = prevRow ? parseInt(prevRow.job_count || '0', 10) : 0;

// Calculate percentage change
let percentChange = 0;
if (previousCount > 0) {
  percentChange = ((currentCount - previousCount) / previousCount) * 100;
} else if (currentCount > 0) {
  percentChange = 100; // New entries count as 100% spike
}

const spikeDetected = percentChange > 50;

return [{
  json: {
    ...current,
    previousCount,
    currentCount,
    percentChange: Math.round(percentChange),
    spikeDetected,
    checkDate: new Date().toISOString().split('T')[0]
  }
}];

